import React, { useEffect, useState } from 'react';
import { Bar, Line } from 'react-chartjs-2';
import { Chart as ChartJS, CategoryScale, LinearScale, BarElement, LineElement, PointElement, Title, Tooltip, Legend } from 'chart.js';
import api from '../api';

ChartJS.register(CategoryScale, LinearScale, BarElement, LineElement, PointElement, Title, Tooltip, Legend);

const AdminDashboard = () => {
  const [users, setUsers] = useState([]);
  const [products, setProducts] = useState([]);
  const [analytics, setAnalytics] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const loadData = async () => {
      try {
        setLoading(true);
        const [usersRes, productsRes, analyticsRes] = await Promise.all([
          api.get('admin/users'),
          api.get('admin/products'),
          api.get('admin/analytics'),
        ]);

        setUsers(usersRes.data);
        setProducts(productsRes.data);
        setAnalytics(analyticsRes.data);
        setError('');
      } catch (err) {
        console.error('Admin dashboard load error:', err);
        const msg = err.response?.data?.message || err.message || 'Failed to load admin analytics';
        setError(msg);
      } finally {
        setLoading(false);
      }
    };

    loadData();
  }, []);

  const toggleBlock = async (userId, blocked) => {
    try {
      await api.put(`admin/users/${userId}/${blocked ? 'unblock' : 'block'}`);
      setUsers(users.map((u) => (u.id === userId ? { ...u, blocked: !blocked } : u)));
    } catch (err) {
      console.error(err);
    }
  };

  const usersPerMonthLabels = analytics ? Object.keys(analytics.usersPerMonth || {}).sort() : [];
  const userDataset = analytics ? usersPerMonthLabels.map((k) => analytics.usersPerMonth[k]) : [];

  const productsCategoryLabels = analytics ? Object.keys(analytics.productsPerCategory || {}) : [];
  const productsCategoryData = analytics ? productsCategoryLabels.map((k) => analytics.productsPerCategory[k]) : [];

  return (
    <div>
      <h2>Admin Dashboard</h2>

      {loading && <p>Loading admin analytics...</p>}
      {error && !loading && <p style={{ color: 'red' }}>Error: {error}</p>}

      {analytics && (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', gap: '16px', marginBottom: '24px' }}>
          {[
            { label: 'Total Users', value: analytics.totalUsers },
            { label: 'Total Products', value: analytics.totalProducts },
            { label: 'Products Sold', value: analytics.productsSold },
            { label: 'Active Listings', value: analytics.activeListings },
          ].map((tile) => (
            <div key={tile.label} style={{ padding: '16px', border: '1px solid #ccc', borderRadius: 8, background: '#fff' }}>
              <h4>{tile.label}</h4>
              <p style={{ fontSize: '1.6rem', margin: 0 }}>{tile.value}</p>
            </div>
          ))}
        </div>
      )}

      <h3>Reports</h3>
      <div>
        {(analytics?.reports || []).map((report) => (
          <div key={report.title} style={{ border: '1px solid #ddd', padding: 10, marginBottom: 8, borderRadius: 6 }}>
            <strong>{report.title}</strong> - {report.value}
            <div style={{ fontSize: '0.9rem', color: '#555' }}>{report.description}</div>
          </div>
        ))}
      </div>

      <h3>Charts</h3>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
        <div style={{ background: '#fff', padding: '16px', borderRadius: 8, border: '1px solid #ddd' }}>
          <h4>Users Registered Per Month</h4>
          <Line
            data={{
              labels: usersPerMonthLabels,
              datasets: [{ label: 'Users', data: userDataset, borderColor: '#4287f5', backgroundColor: 'rgba(66, 135, 245, 0.2)', tension: 0.4 }],
            }}
            options={{ responsive: true, plugins: { legend: { display: false } } }}
          />
        </div>

        <div style={{ background: '#fff', padding: '16px', borderRadius: 8, border: '1px solid #ddd' }}>
          <h4>Products Per Category</h4>
          <Bar
            data={{
              labels: productsCategoryLabels,
              datasets: [{ label: 'Products', data: productsCategoryData, backgroundColor: 'rgba(75, 192, 192, 0.6)' }],
            }}
            options={{ responsive: true, plugins: { legend: { display: false } } }}
          />
        </div>
      </div>

      <h3>User Management</h3>
      {users.map((u) => (
        <div key={u.id} style={{ border: '1px solid #ccc', marginBottom: 8, padding: 8 }}>
          <p>{u.name} ({u.email}) - {u.role} - {u.blocked ? 'Blocked' : 'Active'}</p>
          <button onClick={() => toggleBlock(u.id, u.blocked)}>{u.blocked ? 'Unblock' : 'Block'}</button>
        </div>
      ))}

      <h3>Product Listings</h3>
      {products.map((p) => (
        <div key={p.id} style={{ border: '1px solid #ccc', marginBottom: 8, padding: 8 }}>
          <p>{p.title} by {p.sellerName}</p>
        </div>
      ))}
    </div>
  );
};

export default AdminDashboard;
